79	func (r *startupHousekeepingRunner) Cleanup(ctx context.Context) (agent.ExecutionCleanupSummary, error) {
80		if r == nil {
81			return agent.ExecutionCleanupSummary{}, nil
82		}
83		report, err := r.scan(ctx, true)
84		if err != nil {
85			return agent.ExecutionCleanupSummary{
86				ProjectRoot: r.projectRoot,
87				TempRoot:    r.tempRoot,
88			}, err
89		}
90		summary := agent.ExecutionCleanupSummary{
91			ProjectRoot:                 report.ProjectRoot,
92			TempRoot:                    report.TempRoot,
93			RemovedRegisteredWorktrees:  report.RemovedRegisteredWorktrees,
94			RemovedUnregisteredTempDirs: report.RemovedUnregisteredTempDirs,
95			RemovedWorkerDirs:           report.RemovedWorkerDirs,
96			RemovedEvidenceDirs:         report.ArchivedExecutionDirs + report.DeletedExecutionDirs,
97			Warnings:                    append([]agent.ExecutionCleanupWarning(nil), report.Warnings...),
98		}
99		if r.processCleanup != nil {
100			now := time.Now().UTC()
101			if r.now != nil {
102				now = r.now()
103			}
104			if procErr := r.processCleanup(ctx, report.ProjectRoot, report.TempRoot, &summary, report.runStates, report.registered, now); procErr != nil {
105				return summary, procErr
106			}
107		}
108		return summary, nil
109	}
