111	func (r *startupHousekeepingRunner) scan(ctx context.Context, apply bool) (startupHousekeepingReport, error) {
112		if r == nil {
113			return startupHousekeepingReport{}, nil
114		}
115		report := startupHousekeepingReport{
116			ProjectRoot: r.projectRoot,
117			TempRoot:    r.tempRoot,
118		}
119		if r.projectRoot == "" {
120			return report, nil
121		}
122		now := time.Now().UTC()
123		if r.now != nil {
124			now = r.now()
