126	
127		runStates, err := agent.ReadRunStates(r.projectRoot)
128		if err != nil {
129			return report, err
130		}
131		report.runStates = append([]agent.RunState(nil), runStates...)
132		if err := r.scanWorktrees(ctx, now, runStates, apply, &report); err != nil {
133			return report, err
