144	func (r *startupHousekeepingRunner) scanWorktrees(ctx context.Context, now time.Time, runStates []agent.RunState, apply bool, report *startupHousekeepingReport) error {
145		if report.TempRoot == "" {
146			return nil
147		}
148		if ctx != nil {
149			if err := ctx.Err(); err != nil {
150				return err
151			}
152		}
153		entries, err := os.ReadDir(report.TempRoot)
154		if err != nil {
155			if os.IsNotExist(err) {
156				return nil
157			}
158			return err
159		}
160	
161		registered := map[string]struct{}{}
162		if paths, listErr := (&agent.RealGitOps{}).WorktreeList(r.projectRoot); listErr == nil {
163			for _, path := range paths {
164				registered[filepath.Clean(path)] = struct{}{}
165			}
166		}
167		report.registered = registered
168	
169		for _, entry := range entries {
170			if !entry.IsDir() || !strings.HasPrefix(entry.Name(), agent.ExecuteBeadWtPrefix) {
171				continue
172			}
173			if ctx != nil {
174				if err := ctx.Err(); err != nil {
175					return err
176				}
177			}
178			info, err := entry.Info()
179			if err != nil {
180				report.Warnings = append(report.Warnings, agent.ExecutionCleanupWarning{
181					Path:    filepath.Join(report.TempRoot, entry.Name()),
182					Class:   "worktree_stat",
183					Message: err.Error(),
184				})
185				continue
186			}
187			if now.Sub(info.ModTime()) < r.worktreeMaxAge {
188				continue
189			}
190	
191			path := filepath.Join(report.TempRoot, entry.Name())
192			meta, metaErr := agent.ReadExecutionCleanupMetadata(path)
193			if metaErr == nil {
194				meta.WorktreePath = firstNonEmpty(meta.WorktreePath, path)
195			} else {
196				meta = agent.ExecutionCleanupMetadata{WorktreePath: path}
197			}
198			if worktreeStillLive(meta, runStates, now) {
199				continue
200			}
201	
202			report.StaleWorktrees++
203			if !apply {
204				continue
205			}
206	
207			if _, ok := registered[filepath.Clean(path)]; ok {
208				if err := (&agent.RealGitOps{}).WorktreeRemove(r.projectRoot, path); err != nil {
209					report.Warnings = append(report.Warnings, agent.ExecutionCleanupWarning{
210						Path:    path,
211						Class:   "registered_worktree_remove",
212						Message: err.Error(),
213					})
214					continue
215				}
216				report.RemovedRegisteredWorktrees++
217				continue
218			}
219	
220			if err := os.RemoveAll(path); err != nil {
221				report.Warnings = append(report.Warnings, agent.ExecutionCleanupWarning{
222					Path:    path,
223					Class:   "unregistered_worktree_remove",
224					Message: err.Error(),
225				})
226				continue
227			}
228			report.RemovedUnregisteredTempDirs++
229		}
230	
231		return nil
232	}
