234	func (r *startupHousekeepingRunner) scanWorkerDirs(ctx context.Context, now time.Time, apply bool, report *startupHousekeepingReport) error {
235		root := workerstatus.LivenessDir(r.projectRoot)
236		entries, err := os.ReadDir(root)
237		if err != nil {
238			if os.IsNotExist(err) {
239				return nil
240			}
241			return err
242		}
243	
244		for _, entry := range entries {
245			if !entry.IsDir() || !strings.HasPrefix(entry.Name(), "agent-loop-") {
246				continue
247			}
248			if ctx != nil {
249				if err := ctx.Err(); err != nil {
250					return err
251				}
252			}
253	
254			rec, err := workerstatus.ReadLiveness(r.projectRoot, entry.Name())
255			if err != nil {
256				report.Warnings = append(report.Warnings, agent.ExecutionCleanupWarning{
257					Path:    filepath.Join(root, entry.Name(), "status.json"),
258					Class:   "worker_dir_read",
259					Message: err.Error(),
260				})
261				continue
262			}
263			stale, _ := staleWorkerDir(rec, now, r.workerDirMaxAge)
264			if !stale {
265				continue
266			}
267	
268			report.StaleWorkerDirs++
269			if !apply {
270				continue
271			}
272	
273			dirPath := filepath.Join(root, entry.Name())
274			if err := os.RemoveAll(dirPath); err != nil {
275				report.Warnings = append(report.Warnings, agent.ExecutionCleanupWarning{
276					Path:    dirPath,
277					Class:   "worker_dir_remove",
278					Message: err.Error(),
279				})
280				continue
281			}
282			report.RemovedWorkerDirs++
283		}
284	
285		return nil
286	}
