288	func (r *startupHousekeepingRunner) scanExecutionDirs(ctx context.Context, now time.Time, runStates []agent.RunState, apply bool, report *startupHousekeepingReport) error {
289		policy := r.retentionPolicy
290		if policy.mode == executionRetentionDisabled {
291			return nil
292		}
293	
294		root := ddxroot.JoinProject(r.projectRoot, "executions")
295		entries, err := os.ReadDir(root)
296		if err != nil {
297			if os.IsNotExist(err) {
298				return nil
299			}
300			return err
301		}
302	
303		activeAttempts := map[string]struct{}{}
304		for _, rs := range runStates {
305			if rs.AttemptID != "" {
306				activeAttempts[rs.AttemptID] = struct{}{}
307			}
308		}
309		cutoff := now.AddDate(0, 0, -policy.days)
310	
311		for _, entry := range entries {
312			if !entry.IsDir() {
313				continue
314			}
315			if _, ok := activeAttempts[entry.Name()]; ok {
316				continue
317			}
318			if ctx != nil {
319				if err := ctx.Err(); err != nil {
320					return err
321				}
322			}
323	
324			dirPath := filepath.Join(root, entry.Name())
325			if !hasExecutionEvidenceMarker(dirPath) {
326				continue
327			}
328	
329			info, err := entry.Info()
330			if err != nil {
331				report.Warnings = append(report.Warnings, agent.ExecutionCleanupWarning{
332					Path:    dirPath,
333					Class:   "execution_dir_stat",
334					Message: err.Error(),
335				})
336				continue
337			}
338			if !info.ModTime().Before(cutoff) {
339				continue
340			}
341	
342			report.StaleExecutionDirs++
343			if !apply {
344				continue
345			}
346	
347			switch policy.mode {
348			case executionRetentionArchive:
349				if err := archiveExecutionDir(r.projectRoot, dirPath, entry.Name(), info.ModTime()); err != nil {
350					report.Warnings = append(report.Warnings, agent.ExecutionCleanupWarning{
351						Path:    dirPath,
352						Class:   "execution_dir_archive",
353						Message: err.Error(),
354					})
355					continue
356				}
357				report.ArchivedExecutionDirs++
358			case executionRetentionDelete:
359				if err := os.RemoveAll(dirPath); err != nil {
360					report.Warnings = append(report.Warnings, agent.ExecutionCleanupWarning{
361						Path:    dirPath,
362						Class:   "execution_dir_remove",
363						Message: err.Error(),
364					})
365					continue
366				}
367				report.DeletedExecutionDirs++
368			}
369		}
370	
371		return nil
372	}
