374	func staleWorkerDir(rec workerstatus.LivenessRecord, now time.Time, maxAge time.Duration) (bool, string) {
375		if rec.PID > 0 && !processAlive(rec.PID) {
376			return true, fmt.Sprintf("worker pid %d is no longer live", rec.PID)
377		}
378		if !rec.LastActivityAt.IsZero() && now.Sub(rec.LastActivityAt) > maxAge {
379			return true, fmt.Sprintf("last activity older than %s", maxAge)
380		}
381		return false, ""
382	}
383	
384	func resolveExecutionRetentionPolicy(projectRoot string) executionRetentionPolicy {
385		if raw := strings.TrimSpace(os.Getenv(executionRetentionOverrideEnv)); raw != "" {
386			if days, err := strconv.Atoi(raw); err == nil && days >= 0 {
387				if days == 0 {
388					return executionRetentionPolicy{days: 0, mode: executionRetentionDelete}
389				}
390				return executionRetentionPolicy{days: days, mode: executionRetentionArchive}
391			}
392		}
393	
394		cfgPath := ddxroot.JoinProject(projectRoot, "config.yaml")
395		cfg, err := config.LoadFromFile(cfgPath)
396		if err != nil || cfg == nil || cfg.Executions == nil {
397			return executionRetentionPolicy{days: 90, mode: executionRetentionArchive}
398		}
399		days := cfg.Executions.ResolveRetainDays()
400		if days == 0 {
401			return executionRetentionPolicy{days: 0, mode: executionRetentionDisabled}
402		}
403		return executionRetentionPolicy{days: days, mode: executionRetentionArchive}
404	}
405	
406	func hasExecutionEvidenceMarker(dirPath string) bool {
407		for _, name := range []string{"result.json", "manifest.json"} {
408			if _, err := os.Stat(filepath.Join(dirPath, name)); err == nil {
409				return true
410			}
411		}
412		return false
413	}
414	
415	func archiveExecutionDir(projectRoot, dirPath, attemptID string, modTime time.Time) error {
416		year, month := executionArchiveBucket(attemptID, modTime.UTC())
417		dstRoot := filepath.Join(projectRoot, filepath.FromSlash(executionRetentionArchiveRoot), year, month)
418		if err := os.MkdirAll(dstRoot, 0o755); err != nil {
419			return fmt.Errorf("mkdir archive dir: %w", err)
420		}
421		dstPath := filepath.Join(dstRoot, attemptID)
422		if _, err := os.Stat(dstPath); err == nil {
423			return fmt.Errorf("archive destination already exists: %s", dstPath)
424		} else if !errors.Is(err, os.ErrNotExist) {
425			return err
426		}
427		return os.Rename(dirPath, dstPath)
428	}
429	
430	func executionArchiveBucket(attemptID string, modTime time.Time) (string, string) {
431		ts := attemptID
432		if idx := strings.IndexByte(ts, '-'); idx >= 0 {
433			ts = ts[:idx]
434		}
435		if parsed, err := time.ParseInLocation(executionRetentionTimestampLayout, ts, time.UTC); err == nil {
436			return parsed.Format("2006"), parsed.Format("01")
437		}
438		if modTime.IsZero() {
439			modTime = time.Now().UTC()
440		}
441		return modTime.Format("2006"), modTime.Format("01")
442	}
