50	func captureAttemptProcessBaseline(ctx context.Context, worktree string) attemptProcessSnapshot {
51		processes, err := scanAttemptProcesses(ctx)
52		if err != nil {
53			return attemptProcessSnapshot{PIDs: map[int]struct{}{}, Err: err.Error()}
54		}
55		pids := make(map[int]struct{}, len(processes))
56		for _, proc := range attemptCleanupCandidates(processes, nil, worktree) {
57			pids[proc.PID] = struct{}{}
58		}
59		return attemptProcessSnapshot{PIDs: pids}
60	}
