62	func cleanupAttemptProcesses(ctx context.Context, projectRoot, beadID, attemptID, worktree string, baseline attemptProcessSnapshot, trigger string) *attemptProcessCleanupReport {
63		started := time.Now().UTC()
64		report := &attemptProcessCleanupReport{
65			AttemptID:   attemptID,
66			BeadID:      beadID,
67			Worktree:    worktree,
68			Trigger:     trigger,
69			StartedAt:   started,
70			BaselineErr: baseline.Err,
71		}
72		processes, err := scanAttemptProcesses(context.Background())
73		if err != nil {
74			report.ScanErr = err.Error()
75			report.FinishedAt = time.Now().UTC()
76			writeAttemptProcessCleanupArtifact(projectRoot, attemptID, report)
77			return report
78		}
79		report.Scanned = len(processes)
80		candidates := attemptCleanupCandidates(processes, baseline.PIDs, worktree)
81		report.Candidates = candidates
82		if len(candidates) == 0 && trigger == "" && baseline.Err == "" {
83			return nil
84		}
85	
86		killAttemptProcesses(candidates, report)
87	
88		after, scanErr := scanAttemptProcesses(context.Background())
89		if scanErr != nil {
90			report.ScanErr = strings.TrimSpace(strings.Join([]string{report.ScanErr, scanErr.Error()}, "\n"))
91		} else {
92			live := map[int]attemptProcessInfo{}
93			for _, proc := range after {
94				live[proc.PID] = proc
95			}
96			for _, proc := range candidates {
97				if current, ok := live[proc.PID]; ok && signalProcessAlive(proc.PID) {
98					report.StillAlive = append(report.StillAlive, current)
99				} else {
100					report.Killed = append(report.Killed, proc)
101				}
102			}
103		}
104		report.FinishedAt = time.Now().UTC()
105		writeAttemptProcessCleanupArtifact(projectRoot, attemptID, report)
106		return report
107	}
