161	func processCommandMentionsAttempt(command, worktree string) bool {
162		if strings.TrimSpace(command) == "" || strings.TrimSpace(worktree) == "" {
163			return false
164		}
165		return strings.Contains(command, worktree) || strings.Contains(command, filepath.Base(worktree))
166	}
167	
168	func processCwdWithin(cwd, root string) bool {
169		if strings.TrimSpace(cwd) == "" || strings.TrimSpace(root) == "" {
170			return false
171		}
172		cleanCwd := canonicalCleanupPath(cwd)
173		cleanRoot := canonicalCleanupPath(root)
174		return cleanCwd == cleanRoot || strings.HasPrefix(cleanCwd, cleanRoot+string(filepath.Separator))
175	}
176	
177	func canonicalCleanupPath(path string) string {
178		abs, err := filepath.Abs(path)
179		if err != nil {
180			abs = filepath.Clean(path)
181		}
182		if real, err := filepath.EvalSymlinks(abs); err == nil {
183			abs = real
184		}
185		return filepath.Clean(abs)
186	}
