84	func (m *ExecutionCleanupManager) cleanupStaleAttemptProcessGroups(
85		ctx context.Context,
86		summary *ExecutionCleanupSummary,
87		runStates []RunState,
88		registered map[string]struct{},
89		probe ExecutionCleanupLivenessProbe,
90		now time.Time,
91	) error {
92		if m == nil || summary == nil {
93			return nil
94		}
95		if probe == nil {
96			probe = defaultExecutionCleanupLivenessProbe{}
97		}
98		if ctx != nil {
99			if err := ctx.Err(); err != nil {
100				return err
101			}
102		}
103		scanner := m.attemptProcessScanner
104		if scanner == nil {
105			scanner = newExecutionCleanupAttemptProcessScanner()
106		}
107		if scanner == nil {
108			return nil
109		}
110		processes, err := scanner.Scan(ctx)
111		if err != nil {
112			if errors.Is(err, errExecutionCleanupAttemptProcessUnavailable) {
113				summary.Warnings = append(summary.Warnings, ExecutionCleanupWarning{
114					Path:    m.ProjectRoot,
115					Class:   "attempt_process_cleanup_unavailable",
116					Message: err.Error(),
117				})
118				summary.ProcessFindings = append(summary.ProcessFindings, ExecutionCleanupProcessFinding{
119					StaleReason: err.Error(),
120				})
121				summary.Observations = append(summary.Observations, ExecutionCleanupObservation{
122					Path:    m.ProjectRoot,
123					Class:   "attempt_process_cleanup_unavailable",
124					Message: err.Error(),
125				})
126				return nil
127			}
128			summary.Warnings = append(summary.Warnings, ExecutionCleanupWarning{
129				Path:    m.ProjectRoot,
130				Class:   "attempt_process_census",
131				Message: err.Error(),
132			})
133			summary.Observations = append(summary.Observations, ExecutionCleanupObservation{
134				Path:    m.ProjectRoot,
135				Class:   "attempt_process_census",
136				Message: err.Error(),
137			})
138			return nil
139		}
140	
141		for _, group := range groupExecutionCleanupAttemptProcesses(processes) {
142			if ctx != nil {
143				if err := ctx.Err(); err != nil {
144					return err
145				}
146			}
147			finding, stale, err := m.classifyExecutionCleanupAttemptProcessGroup(group.Members, runStates, registered, probe, now, summary)
148			if err != nil {
149				summary.Warnings = append(summary.Warnings, ExecutionCleanupWarning{
150					Path:    m.ProjectRoot,
151					Class:   "attempt_process_classify",
152					Message: err.Error(),
153				})
154				summary.Observations = append(summary.Observations, ExecutionCleanupObservation{
155					Path:    m.ProjectRoot,
156					Class:   "preserved_uncertain_attempt_process",
157					Message: err.Error(),
158				})
159				continue
160			}
161			if !stale {
162				continue
163			}
164			finding.WouldKill = true
165			observation := ExecutionCleanupObservation{
166				Path:    finding.Worktree,
167				Message: finding.StaleReason,
168			}
169			if m.DryRun {
170				observation.Class = "would_reap_stale_attempt_process"
171			} else {
172				observation.Class = "reaped_stale_attempt_process"
173			}
174			if !m.DryRun {
175				killer := m.attemptProcessKiller
176				if killer == nil {
177					killer = newExecutionCleanupAttemptProcessKiller()
178				}
179				if killer != nil {
180					if killErr := killer.KillGroup(finding.PGID); killErr != nil {
181						summary.Warnings = append(summary.Warnings, ExecutionCleanupWarning{
182							Path:    finding.Worktree,
183							Class:   "attempt_process_kill",
184							Message: killErr.Error(),
185						})
186						observation.Class = "cannot_reap_stale_attempt_process"
187						observation.Message = killErr.Error()
188						summary.ProcessFindings = append(summary.ProcessFindings, finding)
189						summary.Observations = append(summary.Observations, observation)
190						continue
191					}
192				}
193				finding.Terminated = true
194			}
195			summary.ProcessFindings = append(summary.ProcessFindings, finding)
196			summary.Observations = append(summary.Observations, observation)
197		}
198		return nil
199	}
