201	func (m *ExecutionCleanupManager) classifyExecutionCleanupAttemptProcessGroup(
202		group []executionCleanupAttemptProcess,
203		runStates []RunState,
204		registered map[string]struct{},
205		probe ExecutionCleanupLivenessProbe,
206		now time.Time,
207		summary *ExecutionCleanupSummary,
208	) (ExecutionCleanupProcessFinding, bool, error) {
209		if len(group) == 0 {
210			return ExecutionCleanupProcessFinding{}, false, nil
211		}
212		var staleProc *executionCleanupAttemptProcess
213		var staleMeta ExecutionCleanupMetadata
214		var staleReason string
215	
216		for i := range group {
217			proc := group[i]
218			if proc.PID <= 0 || proc.Worktree == "" {
219				continue
220			}
221			if !isPathWithin(proc.Worktree, m.tempRoot()) {
222				continue
223			}
224	
225			meta, err := ReadExecutionCleanupMetadata(proc.Worktree)
226			candidateRunStates := runStates
227			var matchedRunState *RunState
228	
229			switch {
230			case err == nil:
231				if _, ok := registered[filepath.Clean(proc.Worktree)]; ok {
232					// Registered worktrees are active project state and are preserved
233					// even when the run-state file has already gone stale.
234					summary.Observations = append(summary.Observations, ExecutionCleanupObservation{
235						Path:    proc.Worktree,
236						Class:   "preserved_registered_worktree_process",
237						Message: "registered worktree is still active",
238					})
239					continue
240				}
241				if meta.ProjectRoot != "" && !sameCleanPath(meta.ProjectRoot, m.ProjectRoot) {
242					if !m.canReclaimForeignTestOwnedPath(meta.ProjectRoot, proc.Worktree) {
243						summary.Observations = append(summary.Observations, ExecutionCleanupObservation{
244							Path:    proc.Worktree,
245							Class:   "preserved_foreign_project_process",
246							Message: fmt.Sprintf("foreign project_root=%s does not match manager project_root=%s", meta.ProjectRoot, m.ProjectRoot),
247						})
248						continue
249					}
250					candidateRunStates = m.runStatesForMetadata(meta, runStates, summary)
251				}
252				matchedRunState = matchingRunStateForMeta(candidateRunStates, meta)
253			case errors.Is(err, os.ErrNotExist):
254				if _, ok := registered[filepath.Clean(proc.Worktree)]; ok {
255					// Registered worktree without metadata stays conservative and
256					// does not get reaped from the process census alone.
257					summary.Observations = append(summary.Observations, ExecutionCleanupObservation{
258						Path:    proc.Worktree,
259						Class:   "preserved_registered_missing_metadata_process",
260						Message: "registered worktree without cleanup metadata",
261					})
262					continue
263				}
264				matchedRunState = matchingRunStateForMeta(runStates, ExecutionCleanupMetadata{WorktreePath: proc.Worktree})
265				if matchedRunState == nil {
266					summary.Observations = append(summary.Observations, ExecutionCleanupObservation{
267						Path:    proc.Worktree,
268						Class:   "preserved_uncertain_attempt_process",
269						Message: "no live run-state or cleanup metadata matched",
270					})
271					continue
272				}
273				meta = candidateCycleMetadataFromRunState(*matchedRunState)
274				meta.ProjectRoot = m.ProjectRoot
275			default:
276				summary.Warnings = append(summary.Warnings, ExecutionCleanupWarning{
277					Path:    proc.Worktree,
278					Class:   "attempt_process_metadata_read",
279					Message: err.Error(),
280				})
281				summary.Observations = append(summary.Observations, ExecutionCleanupObservation{
282					Path:    proc.Worktree,
283					Class:   "preserved_uncertain_attempt_process",
284					Message: err.Error(),
285				})
286				continue
287			}
288	
289			live, reason := probe.IsLive(meta, matchedRunState, now)
290			if live {
291				summary.Observations = append(summary.Observations, ExecutionCleanupObservation{
292					Path:    proc.Worktree,
293					Class:   "preserved_live_attempt_process",
294					Message: reason,
295				})
296				return ExecutionCleanupProcessFinding{}, false, nil
297			}
298	
299			if staleProc == nil {
300				staleCopy := proc
301				staleProc = &staleCopy
302				staleMeta = meta
303				staleReason = reason
304			}
305		}
306	
307		if staleProc == nil {
308			return ExecutionCleanupProcessFinding{}, false, nil
309		}
310	
311		finding := ExecutionCleanupProcessFinding{
312			PID:         staleProc.PID,
313			PPID:        staleProc.PPID,
314			PGID:        staleProc.PGID,
315			BeadID:      staleMeta.BeadID,
316			AttemptID:   staleMeta.AttemptID,
317			Command:     staleProc.Command,
318			Cwd:         staleProc.Cwd,
319			Worktree:    staleProc.Worktree,
320			StartedAt:   staleProc.StartedAt,
321			StaleReason: staleReason,
322			WouldKill:   true,
323			Members:     make([]ExecutionCleanupProcessFact, 0, len(group)),
324		}
325		if finding.PGID <= 0 {
326			finding.PGID = finding.PID
327		}
328		for _, proc := range group {
329			finding.Members = append(finding.Members, ExecutionCleanupProcessFact(proc))
330		}
331		return finding, true, nil
332	}
