387	func executionCleanupAttemptWorktreeRoot(path string) string {
388		path = strings.TrimSpace(path)
389		if path == "" {
390			return ""
391		}
392		path = strings.TrimSuffix(path, " (deleted)")
393		if !strings.Contains(path, ExecuteBeadWtPrefix) {
394			return ""
395		}
396		start := strings.Index(path, ExecuteBeadWtPrefix)
397		if start < 0 {
398			return ""
399		}
400		end := start + len(ExecuteBeadWtPrefix)
401		for end < len(path) {
402			switch path[end] {
403			case '/', '\\', ' ', '\t', '\x00':
404				return filepath.Clean(path[:end])
405			}
406			end++
407		}
408		return filepath.Clean(path)
409	}
