415	func executionCleanupAttemptProcessFromWorkerStatus(cmdline, cwd string, pid, ppid, pgid int, startedAt time.Time, tempRoot string) executionCleanupAttemptProcess {
416		_, worktree := workerstatus.InferBead(cmdline, cwd)
417		worktree = executionCleanupAttemptWorktreeRoot(worktree)
418		// Fallback: classify reparented DDx descendants whose cwd lives under the
419		// configured execution worktree root, even when the cwd no longer carries
420		// the `.execute-bead-wt-*` segment (e.g. provider subprocess that inherited
421		// the parent cwd, then its parent died and it was reparented to init).
422		if worktree == "" && tempRoot != "" && cwd != "" {
423			trimmedCwd := strings.TrimSuffix(strings.TrimSpace(cwd), " (deleted)")
424			if trimmedCwd != "" && isPathWithin(trimmedCwd, tempRoot) {
425				worktree = filepath.Clean(trimmedCwd)
426			}
427		}
428		return executionCleanupAttemptProcess{
429			PID:       pid,
430			PPID:      ppid,
431			PGID:      pgid,
432			Command:   cmdline,
433			Cwd:       cwd,
434			Worktree:  worktree,
435			StartedAt: startedAt,
436		}
437	}
